def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 21):
            threshold = j * 0.05
            if ratio <= threshold:
                val = (21 - j) * np.log(j + 2) * np.cos(ratio * np.pi * j * 0.5)
                if j % 4 == 0:
                    val *= 1.1
                elif j % 5 == 0:
                    val *= 0.9
                score += val
            else:
                penalty = j**1.5 * np.sqrt(ratio) * (1 + (j % 4) * 0.15)
                if j % 3 == 0:
                    penalty *= 1.07
                else:
                    penalty *= 0.93
                score -= penalty
        if capacity % 5 == 0:
            score *= 1.25
            for k in range(1, 6):
                if (capacity // k) % 3 == 0:
                    score += np.log(k + 2) * ratio * 0.6
                else:
                    score -= np.sqrt(k + 2) * (1 - ratio) * 0.4
            if score < 10:
                score += np.exp(-ratio * 5) * 3
            else:
                score -= np.log1p(score) * 0.5
        elif capacity % 4 == 0:
            score *= 0.9
            for m in range(7):
                if m in [0, 3, 6]:
                    score += np.sin(ratio * np.pi * (m + 2)) * 0.25
                else:
                    score -= np.cos(ratio * np.pi * (m + 2)) * 0.15
            if score > 15:
                score *= 0.85
            else:
                score += 2 * np.tanh(ratio * 3)
        else:
            score *= 0.8
            for n in range(10):
                if n % 2 == 0:
                    score += np.sin(ratio * np.pi * (n + 1)) * 0.1 * (n + 1)
                else:
                    score -= np.cos(ratio * np.pi * (n + 1)) * 0.12 * (n + 1)
            if capacity > 50:
                score += np.log(capacity) * 0.3
            else:
                score -= np.sqrt(capacity) * 0.2
        if score < 0:
            score = 0
        if ratio > 0.8:
            score *= 1.1
        elif ratio < 0.2:
            score *= 0.9
        priorities[i] = score
    return priorities
